--
-- Name: adjust_inventory_stock(uuid, uuid, uuid, numeric, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.adjust_inventory_stock(p_org_id uuid, p_product_id uuid, p_warehouse_id uuid, p_diff numeric, p_batch_number text DEFAULT NULL::text, p_bin_id uuid DEFAULT NULL::uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    INSERT INTO public.inventory_stocks (
        org_id, product_id, warehouse_id, quantity, batch_number, bin_id
    ) VALUES (
        p_org_id, p_product_id, p_warehouse_id, p_diff, p_batch_number, p_bin_id
    )
    ON CONFLICT (product_id, warehouse_id, COALESCE(batch_number, ''), COALESCE(bin_id, '00000000-0000-0000-0000-000000000000')) DO UPDATE
    SET quantity = inventory_stocks.quantity + EXCLUDED.quantity,
        updated_at = NOW();
END;
$$;


--
-- Name: auto_journal_bank_transaction(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_journal_bank_transaction() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_je_id UUID;
  v_bank_gl_account_id UUID;
  v_opp_gl_account_id UUID;
  v_ref_type journal_reference_type;
  v_bank_branch_id UUID;
BEGIN
  SELECT account_id, branch_id
  INTO v_bank_gl_account_id, v_bank_branch_id
  FROM public.bank_accounts
  WHERE id = NEW.bank_account_id
    AND org_id = NEW.org_id;

  IF v_bank_gl_account_id IS NULL THEN
    RAISE EXCEPTION 'Bank account % tidak ditemukan untuk organisasi %', NEW.bank_account_id, NEW.org_id;
  END IF;

  IF NEW.branch_id IS NULL THEN
    NEW.branch_id := COALESCE(v_bank_branch_id, public.resolve_single_active_branch(NEW.org_id));
  END IF;

  IF NEW.branch_id IS NULL THEN
    RAISE EXCEPTION 'branch_id is required for bank transaction journaling on organization %', NEW.org_id;
  END IF;

  IF v_bank_branch_id IS NOT NULL AND NEW.branch_id IS DISTINCT FROM v_bank_branch_id THEN
    RAISE EXCEPTION 'bank transaction branch % does not match bank account branch %', NEW.branch_id, v_bank_branch_id;
  END IF;

  v_opp_gl_account_id := NEW.category_id;

  IF v_opp_gl_account_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF NEW.type = 'IN' THEN
    v_ref_type := 'CASH_IN';
  ELSE
    v_ref_type := 'CASH_OUT';
  END IF;

  INSERT INTO public.journal_entries (
    org_id,
    branch_id,
    entry_date,
    description,
    reference_type,
    reference_id,
    status,
    is_auto,
    created_by
  ) VALUES (
    NEW.org_id,
    NEW.branch_id,
    NEW.transaction_date,
    NEW.description,
    v_ref_type,
    NEW.id,
    'POSTED',
    TRUE,
    NEW.created_by
  ) RETURNING id INTO v_je_id;

  IF NEW.type = 'IN' THEN
    INSERT INTO public.journal_lines (entry_id, account_id, debit, credit, memo)
    VALUES (v_je_id, v_bank_gl_account_id, NEW.amount, 0, NEW.description);

    INSERT INTO public.journal_lines (entry_id, account_id, debit, credit, memo)
    VALUES (v_je_id, v_opp_gl_account_id, 0, NEW.amount, NEW.description);
  ELSE
    INSERT INTO public.journal_lines (entry_id, account_id, debit, credit, memo)
    VALUES (v_je_id, v_opp_gl_account_id, NEW.amount, 0, NEW.description);

    INSERT INTO public.journal_lines (entry_id, account_id, debit, credit, memo)
    VALUES (v_je_id, v_bank_gl_account_id, 0, NEW.amount, NEW.description);
  END IF;

  NEW.journal_entry_id := v_je_id;
  RETURN NEW;
END;
$$;


--
-- Name: bootstrap_org_member_units(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bootstrap_org_member_units() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.is_active IS NOT TRUE THEN
    RETURN NEW;
  END IF;

  IF NEW.role IN ('owner', 'admin') THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.org_member_units (org_member_id, org_id, branch_id)
  SELECT NEW.id, NEW.org_id, b.id
  FROM public.branches b
  WHERE b.org_id = NEW.org_id
    AND b.is_active = TRUE
  ON CONFLICT (org_member_id, branch_id) DO NOTHING;

  RETURN NEW;
END;
$$;


--
-- Name: bootstrap_single_branch_member_units(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bootstrap_single_branch_member_units() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_single_branch_id UUID;
  v_active_branch_count INTEGER;
BEGIN
  IF COALESCE(NEW.is_active, FALSE) IS NOT TRUE THEN
    RETURN NEW;
  END IF;

  SELECT COUNT(*)::INTEGER
  INTO v_active_branch_count
  FROM public.branches
  WHERE org_id = NEW.org_id
    AND is_active = TRUE;

  IF v_active_branch_count <> 1 THEN
    RETURN NEW;
  END IF;

  SELECT b.id
  INTO v_single_branch_id
  FROM public.branches b
  WHERE b.org_id = NEW.org_id
    AND b.is_active = TRUE
  ORDER BY b.created_at ASC, b.id ASC
  LIMIT 1;

  IF v_single_branch_id IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.org_member_units (org_member_id, org_id, branch_id)
  SELECT
    om.id,
    om.org_id,
    v_single_branch_id
  FROM public.org_members om
  WHERE om.org_id = NEW.org_id
    AND om.is_active = TRUE
    AND om.role NOT IN ('owner', 'admin')
    AND NOT EXISTS (
      SELECT 1
      FROM public.org_member_units omu
      WHERE omu.org_member_id = om.id
    )
  ON CONFLICT (org_member_id, branch_id) DO NOTHING;

  RETURN NEW;
END;
$$;


--
-- Name: can_access_branch(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_branch(p_org_id uuid, p_branch_id uuid) RETURNS boolean
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.org_members om
    WHERE om.org_id = p_org_id
      AND om.user_id = auth.uid()
      AND om.is_active = TRUE
      AND om.role IN ('owner', 'admin')
  )
  OR EXISTS (
    SELECT 1
    FROM public.org_members om
    JOIN public.org_member_units omu ON omu.org_member_id = om.id
    WHERE om.org_id = p_org_id
      AND om.user_id = auth.uid()
      AND om.is_active = TRUE
      AND omu.branch_id = p_branch_id
  );
$$;


--
-- Name: check_all_journals_balance(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_all_journals_balance() RETURNS TABLE(entry_id uuid, entry_number text, description text, debit_total numeric, credit_total numeric, diff numeric)
    LANGUAGE sql SECURITY DEFINER
    AS $$
    SELECT 
        je.id,
        je.entry_number,
        je.description,
        SUM(jl.debit) as debit_total,
        SUM(jl.credit) as credit_total,
        SUM(jl.debit) - SUM(jl.credit) as diff
    FROM journal_entries je
    JOIN journal_lines jl ON je.id = jl.entry_id
    GROUP BY je.id, je.entry_number, je.description
    HAVING SUM(jl.debit) != SUM(jl.credit);
$$;


--
-- Name: check_cash_balance(uuid, uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_cash_balance(p_org_id uuid, p_account_id uuid, p_amount numeric) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_cash_normal_balance TEXT;
    v_cash_total_debit DECIMAL;
    v_cash_total_credit DECIMAL;
    v_cash_balance DECIMAL;
BEGIN
    SELECT total_debit, total_credit INTO v_cash_total_debit, v_cash_total_credit 
    FROM public.account_balances 
    WHERE org_id = p_org_id AND account_id = p_account_id;
    
    -- Cash/Bank is an Asset (Normal DEBIT)
    v_cash_balance := COALESCE(v_cash_total_debit, 0) - COALESCE(v_cash_total_credit, 0);
    
    IF v_cash_balance < p_amount THEN
        RETURN FALSE;
    END IF;

    RETURN TRUE;
END;
$$;


--
-- Name: check_closed_period(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_closed_period() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_org_id UUID;
  v_entry_date DATE;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_org_id := OLD.org_id;
    v_entry_date := OLD.entry_date;
  ELSE
    v_org_id := NEW.org_id;
    v_entry_date := NEW.entry_date;
  END IF;

  IF v_org_id IS NULL OR v_entry_date IS NULL THEN
    IF TG_OP = 'DELETE' THEN
      RETURN OLD;
    END IF;
    RETURN NEW;
  END IF;

  IF EXISTS (
    SELECT 1 FROM fiscal_periods
    WHERE org_id = v_org_id
      AND is_closed = TRUE
      AND v_entry_date BETWEEN start_date AND end_date
  ) THEN
    RAISE EXCEPTION 'Transaction is within a closed fiscal period and cannot be modified.';
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: check_inventory_ledger_sync(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_inventory_ledger_sync(p_org_id uuid) RETURNS TABLE(product_id uuid, product_name text, stock_qty numeric, avg_cost numeric, on_hand_value numeric, ledger_value numeric, variance numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_gl_inventory_acc_id UUID;
BEGIN
    -- 1. Cari Akun Persediaan Utama (Default: 1401)
    SELECT id INTO v_gl_inventory_acc_id FROM accounts WHERE org_id = p_org_id AND code = '1401' LIMIT 1;
    
    RETURN QUERY
    WITH stock_calc AS (
        SELECT 
            p.id,
            p.name,
            COALESCE(SUM(s.quantity), 0) as total_qty,
            COALESCE(p.average_cost, 0) as avg_cost
        FROM products p
        LEFT JOIN inventory_stocks s ON p.id = s.product_id
        WHERE p.org_id = p_org_id
        GROUP BY p.id, p.name, p.average_cost
    ),
    ledger_calc AS (
        -- Hitung saldo di buku besar untuk akun 1401 per produk jika ada reference_id
        -- Namun di sistem kita, jurnal perolehan biasanya glongongan per FO/PO.
        -- Sebagai dashboard audit, kita bandingkan Total On-Hand Value vs Saldo Akun 1401
        SELECT 
            SUM(debit - credit) as balance
        FROM journal_lines jl
        JOIN journal_entries je ON jl.entry_id = je.id
        WHERE je.org_id = p_org_id 
        AND je.status = 'POSTED'
        AND jl.account_id = v_gl_inventory_acc_id
    )
    SELECT 
        sc.id,
        sc.name,
        sc.total_qty,
        sc.avg_cost::DECIMAL(19,4),
        (sc.total_qty * sc.avg_cost)::DECIMAL(19,4) as on_hand_value,
        (lc.balance / (SELECT COUNT(*) FROM stock_calc WHERE total_qty > 0)) as ledger_value_allocated, -- Simplified allocation
        ((sc.total_qty * sc.avg_cost) - (lc.balance / (SELECT NULLIF(COUNT(*), 0) FROM stock_calc WHERE total_qty > 0))) as variance
    FROM stock_calc sc, ledger_calc lc;
END;
$$;


--
-- Name: check_purchase_payment_limit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_purchase_payment_limit() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_total numeric;
  v_grand_total numeric;
BEGIN
  SELECT grand_total INTO v_grand_total FROM purchases WHERE id = NEW.purchase_id;
  SELECT COALESCE(SUM(amount), 0) INTO v_total 
    FROM purchase_payments 
    WHERE purchase_id = NEW.purchase_id AND id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::uuid);

  IF (v_total + NEW.amount) > v_grand_total THEN
    RAISE EXCEPTION 'Pembayaran melebihi total faktur. Outstanding: %', (v_grand_total - v_total);
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: check_sale_payment_limit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_sale_payment_limit() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_total numeric;
  v_grand_total numeric;
BEGIN
  SELECT grand_total INTO v_grand_total FROM sales WHERE id = NEW.sale_id;
  SELECT COALESCE(SUM(amount), 0) INTO v_total 
    FROM sales_payments 
    WHERE sale_id = NEW.sale_id AND id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::uuid);

  IF (v_total + NEW.amount) > v_grand_total THEN
    RAISE EXCEPTION 'Pembayaran melebihi total faktur. Outstanding: %', (v_grand_total - v_total);
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: check_transaction_protection(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_transaction_protection() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Jika ada jurnal dengan reference_id ini yang sudah POSTED, blokir delete.
    IF EXISTS (SELECT 1 FROM public.journal_entries WHERE reference_id = OLD.id AND status = 'POSTED') THEN
        RAISE EXCEPTION 'TRANSAKSI TERKUNCI: Transaksi ini sudah memiliki jurnal yang sah. Batalkan jurnal terlebih dahulu.';
    END IF;
    RETURN OLD;
END;
$$;


--
-- Name: create_fleet_medical_record(uuid, uuid, date, text, text, numeric, numeric, text, text, jsonb, numeric, date, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_fleet_medical_record(p_org_id uuid, p_asset_id uuid, p_service_date date, p_description text, p_maintenance_type text, p_cost numeric, p_odometer_at numeric, p_technician_name text DEFAULT NULL::text, p_vendor_name text DEFAULT NULL::text, p_parts_replaced jsonb DEFAULT '[]'::jsonb, p_next_service_km numeric DEFAULT NULL::numeric, p_next_service_date date DEFAULT NULL::date, p_attachment_url text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_record_id UUID;
BEGIN
  UPDATE public.fleet_assets
  SET status = 'MAINTENANCE',
      updated_at = NOW()
  WHERE org_id = p_org_id
    AND id = p_asset_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Armada tidak ditemukan atau tidak dapat diakses.';
  END IF;

  INSERT INTO public.fleet_maintenance_labs (
    org_id,
    asset_id,
    service_date,
    description,
    maintenance_type,
    cost,
    odometer_at,
    technician_name,
    vendor_name,
    parts_replaced,
    next_service_km,
    next_service_date,
    attachment_url
  )
  VALUES (
    p_org_id,
    p_asset_id,
    p_service_date,
    p_description,
    p_maintenance_type,
    p_cost,
    p_odometer_at,
    p_technician_name,
    p_vendor_name,
    COALESCE(p_parts_replaced, '[]'::jsonb),
    p_next_service_km,
    p_next_service_date,
    p_attachment_url
  )
  RETURNING id INTO v_record_id;

  RETURN v_record_id;
END;
$$;


--
-- Name: debug_org_inventory(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.debug_org_inventory(p_org_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_products_count INTEGER;
    v_stocks_count INTEGER;
    v_total_value NUMERIC := 0;
BEGIN
    SELECT count(*) INTO v_products_count FROM products WHERE org_id = p_org_id;
    SELECT count(*) INTO v_stocks_count FROM inventory_stocks WHERE org_id = p_org_id;
    
    SELECT COALESCE(SUM(s.quantity * p.average_cost), 0) INTO v_total_value
    FROM inventory_stocks s
    JOIN products p ON s.product_id = p.id
    WHERE s.org_id = p_org_id;

    RETURN jsonb_build_object(
        'org_id', p_org_id,
        'products_count', v_products_count,
        'stocks_count', v_stocks_count,
        'logic_value', v_total_value
    );
END;
$$;


--
-- Name: fix_missing_payroll_lines(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fix_missing_payroll_lines(p_run_id uuid, p_org_id uuid, p_bank_acc_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_entry_id UUID;
    v_expense_acc_id UUID;
    v_amount NUMERIC;
    v_desc TEXT;
BEGIN
    -- 1. Get Run Details
    SELECT journal_entry_id, total_net, 'Pembayaran Gaji Periode ' || period_start || ' s/d ' || period_end
    INTO v_entry_id, v_amount, v_desc
    FROM payroll_runs 
    WHERE id = p_run_id AND org_id = p_org_id;

    IF v_entry_id IS NULL THEN
        RAISE EXCEPTION 'Payroll Run has no linked Journal Entry Header';
    END IF;

    -- 2. Get Expense Account (6001)
    SELECT id INTO v_expense_acc_id FROM accounts WHERE org_id = p_org_id AND code = '6001';
    IF v_expense_acc_id IS NULL THEN
        RAISE EXCEPTION 'Expense Account 6001 not found';
    END IF;

    -- 3. Check if lines already exist (to avoid double insert)
    IF EXISTS (SELECT 1 FROM journal_lines WHERE entry_id = v_entry_id) THEN
        RETURN;
    END IF;

    -- 4. INSERT LINES (Bypassing RLS because of SECURITY DEFINER)
    -- Debit Expense
    INSERT INTO journal_lines (entry_id, account_id, debit, credit, memo)
    VALUES (v_entry_id, v_expense_acc_id, v_amount, 0, v_desc);

    -- Credit Bank
    INSERT INTO journal_lines (entry_id, account_id, debit, credit, memo)
    VALUES (v_entry_id, p_bank_acc_id, 0, v_amount, v_desc);

END;
$$;


--
-- Name: generate_entry_number(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_entry_number(p_org_id uuid) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_year  TEXT := TO_CHAR(NOW(), 'YYYY');
  v_count INT;
BEGIN
  SELECT COUNT(*) + 1 INTO v_count
  FROM journal_entries
  WHERE org_id = p_org_id
    AND EXTRACT(YEAR FROM created_at) = EXTRACT(YEAR FROM NOW());

  RETURN 'JE-' || v_year || '-' || LPAD(v_count::TEXT, 6, '0');
END;
$$;


--
-- Name: generate_maintenance_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_maintenance_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_year TEXT := TO_CHAR(NOW(), 'YYYY');
  v_count INTEGER;
BEGIN
  SELECT COUNT(*) + 1 INTO v_count 
  FROM public.fleet_maintenance_labs 
  WHERE org_id = NEW.org_id 
    AND TO_CHAR(created_at, 'YYYY') = v_year;
    
  NEW.maintenance_number := 'MT-' || v_year || '-' || LPAD(v_count::TEXT, 5, '0');
  RETURN NEW;
END;
$$;


--
-- Name: generate_payslips_for_run(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_payslips_for_run(p_run_id uuid) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_run RECORD;
    v_employee RECORD;
    v_component RECORD;
    v_payslip_id UUID;
    v_basic_salary NUMERIC;
    v_total_earnings NUMERIC := 0;
    v_total_deductions NUMERIC := 0;
    v_net_salary NUMERIC := 0;
    v_amount NUMERIC;
    v_basic_salary_account_id UUID;
    v_count INTEGER := 0;
BEGIN
    SELECT * INTO v_run FROM public.payroll_runs WHERE id = p_run_id;
    
    IF v_run.org_id IS NULL THEN
        RAISE EXCEPTION 'Payroll run not found.';
    END IF;

    IF v_run.branch_id IS NULL THEN
        RAISE EXCEPTION 'Payroll run branch context is required.';
    END IF;

    IF v_run.status = 'PAID' THEN
        RAISE EXCEPTION 'Cannot re-generate slips for a PAID run.';
    END IF;

    DELETE FROM public.payslips WHERE run_id = p_run_id;

    SELECT id INTO v_basic_salary_account_id FROM public.accounts
    WHERE org_id = v_run.org_id AND code = '6001' LIMIT 1;
    
    IF v_basic_salary_account_id IS NULL THEN
        SELECT id INTO v_basic_salary_account_id FROM public.accounts
        WHERE org_id = v_run.org_id AND (code LIKE '6%' OR name ILIKE '%Beban Gaji%') LIMIT 1;
    END IF;

    FOR v_employee IN
        SELECT id, first_name, last_name, basic_salary, branch_id
        FROM public.employees
        WHERE org_id = v_run.org_id
          AND branch_id = v_run.branch_id
          AND employment_status NOT IN ('TERMINATED', 'RESIGNED')
    LOOP
        v_basic_salary := v_employee.basic_salary;
        v_total_earnings := 0;
        v_total_deductions := 0;

        INSERT INTO public.payslips (run_id, branch_id, employee_id, basic_salary, net_salary)
        VALUES (p_run_id, v_run.branch_id, v_employee.id, v_basic_salary, 0)
        RETURNING id INTO v_payslip_id;

        INSERT INTO public.payslip_lines (payslip_id, component_name, type, amount, account_id)
        VALUES (v_payslip_id, 'Gaji Pokok', 'EARNING', v_basic_salary, v_basic_salary_account_id);

        FOR v_component IN
            SELECT
                pc.id, pc.account_id, pc.name, pc.type,
                COALESCE(ec.amount, pc.default_amount) as amount,
                pc.is_percentage, pc.percentage_value
            FROM public.payroll_components pc
            LEFT JOIN public.employee_components ec ON pc.id = ec.component_id AND ec.employee_id = v_employee.id
            WHERE pc.org_id = v_run.org_id
              AND (ec.is_active IS TRUE OR ec.id IS NULL)
        LOOP
            IF v_component.is_percentage THEN
                v_amount := (v_component.percentage_value / 100.0) * v_basic_salary;
            ELSE
                v_amount := v_component.amount;
            END IF;

            INSERT INTO public.payslip_lines (payslip_id, component_id, account_id, component_name, type, amount)
            VALUES (v_payslip_id, v_component.id, v_component.account_id, v_component.name, v_component.type, v_amount);

            IF v_component.type IN ('EARNING', 'BENEFIT') THEN
                v_total_earnings := v_total_earnings + v_amount;
            ELSIF v_component.type IN ('DEDUCTION', 'TAX') THEN
                v_total_deductions := v_total_deductions + v_amount;
            END IF;
        END LOOP;

        v_net_salary := v_basic_salary + v_total_earnings - v_total_deductions;
        
        UPDATE public.payslips SET
            gross_salary = v_basic_salary + v_total_earnings,
            total_deductions = v_total_deductions,
            net_salary = v_net_salary
        WHERE id = v_payslip_id;

        v_count := v_count + 1;
    END LOOP;

    UPDATE public.payroll_runs SET
        total_gross = COALESCE((SELECT SUM(gross_salary) FROM public.payslips WHERE run_id = p_run_id), 0),
        total_deductions = COALESCE((SELECT SUM(total_deductions) FROM public.payslips WHERE run_id = p_run_id), 0),
        total_net = COALESCE((SELECT SUM(net_salary) FROM public.payslips WHERE run_id = p_run_id), 0)
    WHERE id = p_run_id;

    RETURN v_count;
END;
$$;


--
-- Name: get_account_ledger_details(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_account_ledger_details(p_account_id uuid, p_limit integer DEFAULT 50) RETURNS TABLE(entry_date date, entry_number text, description text, debit numeric, credit numeric, reference_type text, reference_id uuid)
    LANGUAGE sql SECURITY DEFINER
    AS $$
    SELECT 
        je.entry_date,
        je.entry_number,
        je.description,
        jl.debit,
        jl.credit,
        je.reference_type::text,
        je.reference_id
    FROM journal_lines jl
    JOIN journal_entries je ON jl.entry_id = je.id
    WHERE jl.account_id = p_account_id
    ORDER BY je.entry_date DESC, je.created_at DESC
    LIMIT p_limit;
$$;


