--
-- Name: audit_logs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.audit_logs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    org_id uuid NOT NULL,
    user_id uuid,
    action text NOT NULL,
    table_name text NOT NULL,
    record_id uuid NOT NULL,
    old_data jsonb,
    new_data jsonb,
    ip_address text,
    user_agent text,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: v_admin_audit_trail; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_admin_audit_trail AS
 SELECT al.id,
    al.org_id,
    al.created_at,
    u.email AS user_email,
    (u.raw_user_meta_data ->> 'full_name'::text) AS user_name,
    al.action,
    al.table_name,
    al.record_id,
    al.old_data,
    al.new_data,
        CASE
            WHEN (al.action = 'CREATE'::text) THEN ('Menambahkan data baru di '::text || al.table_name)
            WHEN (al.action = 'UPDATE'::text) THEN ('Mengubah data di '::text || al.table_name)
            WHEN (al.action = 'DELETE'::text) THEN ('Menghapus data dari '::text || al.table_name)
            WHEN (al.action = 'VOID'::text) THEN ('Membatalkan (VOID) transaksi di '::text || al.table_name)
            ELSE ((al.action || ' pada '::text) || al.table_name)
        END AS description
   FROM (public.audit_logs al
     LEFT JOIN auth.users u ON ((al.user_id = u.id)))
  ORDER BY al.created_at DESC;


--
-- Name: VIEW v_admin_audit_trail; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_admin_audit_trail IS 'View audit trail yang lebih manusiawi untuk dibaca di Dashboard Admin.';


--
-- Name: get_admin_audit_trail(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_admin_audit_trail(p_limit integer DEFAULT 50) RETURNS SETOF public.v_admin_audit_trail
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT * FROM v_admin_audit_trail
    WHERE org_id IN (
        SELECT m.org_id FROM org_members m 
        WHERE m.user_id = auth.uid() 
        AND m.role IN ('owner', 'admin') 
        AND m.is_active = TRUE
    )
    LIMIT p_limit;
END;
$$;


--
-- Name: get_ap_aging_report(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_ap_aging_report(p_org_id uuid) RETURNS TABLE(contact_name text, doc_number text, due_date date, grand_total numeric, paid_amount numeric, outstanding numeric, days_overdue integer, aging_bucket text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        c.name,
        pur.purchase_number,
        pur.due_date,
        pur.grand_total::DECIMAL(19,4),
        COALESCE(pay.total_paid, 0)::DECIMAL(19,4) as paid_amount,
        (pur.grand_total - COALESCE(pay.total_paid, 0))::DECIMAL(19,4) as outstanding,
        GREATEST(0, (CURRENT_DATE - pur.due_date))::INT as days_overdue,
        CASE 
            WHEN (pur.due_date >= CURRENT_DATE) THEN 'Current'
            WHEN (CURRENT_DATE - pur.due_date) <= 30 THEN '0-30 Days'
            WHEN (CURRENT_DATE - pur.due_date) <= 60 THEN '31-60 Days'
            WHEN (CURRENT_DATE - pur.due_date) <= 90 THEN '61-90 Days'
            ELSE '> 90 Days'
        END as aging_bucket
    FROM purchases pur
    JOIN contacts c ON pur.vendor_id = c.id
    LEFT JOIN (
        SELECT purchase_id, SUM(amount) as total_paid 
        FROM purchase_payments 
        GROUP BY purchase_id
    ) pay ON pay.purchase_id = pur.id
    WHERE pur.org_id = p_org_id
    AND pur.status NOT IN ('DRAFT', 'VOIDED')
    AND (pur.grand_total - COALESCE(pay.total_paid, 0)) > 0.01
    ORDER BY days_overdue DESC;
END;
$$;


--
-- Name: get_ar_aging_report(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_ar_aging_report(p_org_id uuid) RETURNS TABLE(contact_name text, doc_number text, due_date date, grand_total numeric, paid_amount numeric, outstanding numeric, days_overdue integer, aging_bucket text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        c.name,
        s.sale_number,
        s.due_date,
        s.grand_total::DECIMAL(19,4),
        COALESCE(p.total_paid, 0)::DECIMAL(19,4) as paid_amount,
        (s.grand_total - COALESCE(p.total_paid, 0))::DECIMAL(19,4) as outstanding,
        GREATEST(0, (CURRENT_DATE - s.due_date))::INT as days_overdue,
        CASE 
            WHEN (s.due_date >= CURRENT_DATE) THEN 'Current'
            WHEN (CURRENT_DATE - s.due_date) <= 30 THEN '0-30 Days'
            WHEN (CURRENT_DATE - s.due_date) <= 60 THEN '31-60 Days'
            WHEN (CURRENT_DATE - s.due_date) <= 90 THEN '61-90 Days'
            ELSE '> 90 Days'
        END as aging_bucket
    FROM sales s
    JOIN contacts c ON s.customer_id = c.id
    LEFT JOIN (
        SELECT sale_id, SUM(amount) as total_paid 
        FROM sales_payments 
        GROUP BY sale_id
    ) p ON p.sale_id = s.id
    WHERE s.org_id = p_org_id
    AND s.status NOT IN ('DRAFT', 'VOIDED')
    AND (s.grand_total - COALESCE(p.total_paid, 0)) > 0.01
    ORDER BY days_overdue DESC;
END;
$$;


--
-- Name: get_attendance_summary(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_attendance_summary(p_employee_id uuid, p_start_date date, p_end_date date) RETURNS TABLE(total_days integer, present_days integer, late_days integer, absent_days integer, sick_days integer, leave_days integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        (p_end_date - p_start_date + 1)::INTEGER,
        COUNT(*) FILTER (WHERE status = 'PRESENT')::INTEGER,
        COUNT(*) FILTER (WHERE status = 'PRESENT' AND check_in > (record_date + interval '9 hours'))::INTEGER, 
        COUNT(*) FILTER (WHERE status = 'ABSENT')::INTEGER,
        COUNT(*) FILTER (WHERE status = 'SICK')::INTEGER,
        COUNT(*) FILTER (WHERE status = 'LEAVE')::INTEGER
    FROM attendance
    WHERE employee_id = p_employee_id
    AND record_date BETWEEN p_start_date AND p_end_date;
END;
$$;


--
-- Name: get_budget_vs_actual(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_budget_vs_actual(p_org_id uuid, p_start_date date, p_end_date date) RETURNS TABLE(account_code text, account_name text, account_type text, budget_amount numeric, actual_amount numeric, variance numeric, variance_percent numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    WITH actuals AS (
        SELECT 
            a.id as acc_id,
            a.code as acc_code,
            a.name as acc_name,
            a.type as acc_type,
            SUM(CASE 
                WHEN a.normal_balance = 'DEBIT' THEN (jl.debit - jl.credit)
                ELSE (jl.credit - jl.debit)
            END) as actual_val
        FROM accounts a
        LEFT JOIN journal_lines jl ON jl.account_id = a.id
        LEFT JOIN journal_entries je ON je.id = jl.entry_id
        WHERE a.org_id = p_org_id
        AND je.status = 'POSTED'
        AND je.entry_date BETWEEN p_start_date AND p_end_date
        GROUP BY a.id, a.code, a.name, a.type
    ),
    budget_agg AS (
        SELECT 
            account_id,
            SUM(budget_amount) as total_budget
        FROM budgets
        WHERE org_id = p_org_id
        AND period BETWEEN p_start_date AND p_end_date
        GROUP BY account_id
    )
    SELECT 
        act.acc_code,
        act.acc_name,
        act.acc_type,
        COALESCE(b.total_budget, 0)::DECIMAL(19,4) as budget_amount,
        COALESCE(act.actual_val, 0)::DECIMAL(19,4) as actual_amount,
        (COALESCE(act.actual_val, 0) - COALESCE(b.total_budget, 0))::DECIMAL(19,4) as variance,
        CASE 
            WHEN COALESCE(b.total_budget, 0) = 0 THEN 
                CASE WHEN COALESCE(act.actual_val, 0) = 0 THEN 0 ELSE 100 END
            ELSE ( (COALESCE(act.actual_val, 0) - b.total_budget) / ABS(b.total_budget) * 100 )::DECIMAL(10,2)
        END as variance_percent
    FROM actuals act
    LEFT JOIN budget_agg b ON b.account_id = act.acc_id
    WHERE COALESCE(b.total_budget, 0) != 0 OR COALESCE(act.actual_val, 0) != 0
    ORDER BY act.acc_code;
END;
$$;


--
-- Name: get_financial_kpis(uuid, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_financial_kpis(p_org_id uuid, p_date date) RETURNS TABLE(kpi_name text, kpi_value numeric, category text, bench_mark text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_total_assets DECIMAL(19,4);
    v_curr_assets DECIMAL(19,4);
    v_curr_liabilities DECIMAL(19,4);
    v_net_profit DECIMAL(19,4);
BEGIN
    -- Hitung Current Assets (Code 11xx - 14xx)
    SELECT SUM(balance) INTO v_curr_assets 
    FROM account_balances 
    WHERE org_id = p_org_id AND code LIKE '1%';

    -- Hitung Current Liabilities (Code 21xx - 24xx)
    SELECT SUM(balance) INTO v_curr_liabilities 
    FROM account_balances 
    WHERE org_id = p_org_id AND code LIKE '2%';

    -- Total Assets
    v_total_assets := v_curr_assets; -- Simplified for now, should include fixed assets (15xx)

    -- Net Profit (All time as of date for ROA)
    SELECT (SUM(total_credit) - SUM(total_debit)) INTO v_net_profit
    FROM account_balances
    WHERE org_id = p_org_id AND code LIKE '4%'; -- Revenue
    
    -- Substract Expenses
    v_net_profit := v_net_profit - (SELECT SUM(total_debit - total_credit) FROM account_balances WHERE org_id = p_org_id AND (code LIKE '5%' OR code LIKE '6%'));

    -- KPI 1: Current Ratio (Liquidity)
    kpi_name := 'Current Ratio';
    kpi_value := COALESCE(v_curr_assets / NULLIF(v_curr_liabilities, 0), 0);
    category := 'LIQUIDITY';
    bench_mark := '> 1.5 Healthy';
    RETURN NEXT;

    -- KPI 2: Net Profit Margin (Profitability)
    kpi_name := 'Net Profit Margin';
    kpi_value := COALESCE(v_net_profit / NULLIF((SELECT SUM(total_credit - total_debit) FROM account_balances WHERE org_id = p_org_id AND code LIKE '4%'), 0), 0) * 100;
    category := 'PROFITABILITY';
    bench_mark := '> 10% Good';
    RETURN NEXT;

    -- KPI 3: Inventory Turnover (Efficiency)
    -- Mock for now: COGS / Avg Inventory
    kpi_name := 'Inventory Health Index';
    kpi_value := (SELECT COUNT(*) FROM products WHERE org_id = p_org_id AND stock_qty > 0);
    category := 'OPERATIONAL';
    bench_mark := '> 0 Active';
    RETURN NEXT;

END;
$$;


--
-- Name: get_inventory_reconciliation(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_inventory_reconciliation(p_org_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_acc_balance NUMERIC;
    v_phys_value NUMERIC;
    v_account_id UUID;
BEGIN
    -- 1. Get Account 1301 Balance
    SELECT id INTO v_account_id FROM accounts WHERE org_id = p_org_id AND code = '1301' LIMIT 1;
    
    IF v_account_id IS NULL THEN
        RETURN jsonb_build_object('error', 'Account 1301 not found');
    END IF;

    SELECT balance INTO v_acc_balance FROM account_balances WHERE account_id = v_account_id;

    -- 2. Get Physical Inventory Value
    SELECT COALESCE(SUM(s.quantity * p.average_cost), 0) INTO v_phys_value
    FROM inventory_stocks s
    JOIN products p ON s.product_id = p.id
    WHERE s.org_id = p_org_id;

    RETURN jsonb_build_object(
        'org_id', p_org_id,
        'account_id', v_account_id,
        'balance_sheet_value', COALESCE(v_acc_balance, 0),
        'inventory_module_value', v_phys_value,
        'discrepancy', COALESCE(v_acc_balance, 0) - v_phys_value
    );
END;
$$;


