END;
$$;


--
-- Name: seed_default_coa_updated(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.seed_default_coa_updated(p_org_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE v_parent_id UUID;
BEGIN
    -- This is a simplified version, ideally I'd update the original function in migration 003
    -- but for now I'll just make sure 6011 is added if missing
    SELECT id INTO v_parent_id FROM accounts WHERE org_id = p_org_id AND code = '6000';
    IF v_parent_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM accounts WHERE org_id = p_org_id AND code = '6011') THEN
        INSERT INTO accounts (org_id, code, name, type, normal_balance, parent_id, is_system)
        VALUES (p_org_id, '6011', 'Kerugian Persediaan (Write-off)', 'EXPENSE', 'DEBIT', v_parent_id, TRUE);
    END IF;
END;
$$;


--
-- Name: seed_default_roles(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.seed_default_roles() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Manager role
  INSERT INTO roles (org_id, name, permissions, is_system) VALUES
  (NEW.id, 'Manager', ARRAY[
    'accounting:read', 'accounting:write',
    'inventory:read', 'inventory:write',
    'sales:read', 'sales:write',
    'purchasing:read', 'purchasing:write',
    'reports:read'
  ], TRUE);

  -- Staff role (limited)
  INSERT INTO roles (org_id, name, permissions, is_system) VALUES
  (NEW.id, 'Staff', ARRAY[
    'accounting:read',
    'inventory:read',
    'sales:read', 'sales:write',
    'purchasing:read'
  ], TRUE);

  -- Viewer role (read-only)
  INSERT INTO roles (org_id, name, permissions, is_system) VALUES
  (NEW.id, 'Viewer', ARRAY[
    'accounting:read',
    'inventory:read',
    'reports:read'
  ], TRUE);

  RETURN NEW;
END;
$$;


--
-- Name: set_adj_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_adj_number() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_suffix TEXT;
BEGIN
  -- Selalu generate nomor baru yang unik, abaikan nilai yang dikirim dari client
  -- Format: ADJ-YYMMDD-HHMMSS-XXXX (hampir mustahil duplikat)
  v_suffix := UPPER(SUBSTRING(MD5(gen_random_uuid()::TEXT), 1, 6));
  NEW.adj_number := 'ADJ-' || TO_CHAR(NOW(), 'YYMMDD-HH24MISS') || '-' || v_suffix;
  RETURN NEW;
END;
$$;


