--
-- Name: validate_journal_balance(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_journal_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_total_debit  NUMERIC;
  v_total_credit NUMERIC;
BEGIN
  -- Only validate when posting (status changing to POSTED)
  IF NEW.status = 'POSTED' AND OLD.status != 'POSTED' THEN
    SELECT
      COALESCE(SUM(debit), 0),
      COALESCE(SUM(credit), 0)
    INTO v_total_debit, v_total_credit
    FROM journal_lines
    WHERE entry_id = NEW.id;

    -- Must have at least 2 lines
    IF (SELECT COUNT(*) FROM journal_lines WHERE entry_id = NEW.id) < 2 THEN
      RAISE EXCEPTION 'Journal entry must have at least 2 lines';
    END IF;

    -- Debit must equal credit
    IF ABS(v_total_debit - v_total_credit) > 0.01 THEN
      RAISE EXCEPTION 'Journal entry is not balanced: debit=% credit=%',
        v_total_debit, v_total_credit;
    END IF;

    -- Set posted_at timestamp
    NEW.posted_at = NOW();
  END IF;

  -- Voided entries cannot be modified
  IF OLD.status = 'VOIDED' THEN
    RAISE EXCEPTION 'Cannot modify a voided journal entry';
  END IF;

  -- Posted entries: only allow status change to VOIDED
  IF OLD.status = 'POSTED' AND NEW.status NOT IN ('VOIDED', 'POSTED') THEN
    RAISE EXCEPTION 'Cannot change a posted entry back to draft';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: validate_journal_balance_on_post(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_journal_balance_on_post() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_total_debit NUMERIC;
  v_total_credit NUMERIC;
BEGIN
  -- Hanya validate saat transisi ke POSTED
  IF NEW.status = 'POSTED' AND (OLD.status IS DISTINCT FROM 'POSTED') THEN
    SELECT 
      COALESCE(SUM(debit), 0),
      COALESCE(SUM(credit), 0)
    INTO v_total_debit, v_total_credit
    FROM journal_lines
    WHERE entry_id = NEW.id;

    IF ABS(v_total_debit - v_total_credit) > 0.01 THEN
      RAISE EXCEPTION 'LEDGER INTEGRITY VIOLATION: Jurnal % tidak balance. Debit: %, Credit: %. Selisih: %',
        NEW.id, v_total_debit, v_total_credit, ABS(v_total_debit - v_total_credit);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: void_payroll_run(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.void_payroll_run(p_run_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_je_id UUID;
BEGIN
    SELECT journal_entry_id INTO v_je_id FROM payroll_runs WHERE id = p_run_id;
    
    -- 1. Void Journal Entry if exists
    IF v_je_id IS NOT NULL THEN
        UPDATE journal_entries SET status = 'VOIDED' WHERE id = v_je_id;
    END IF;

    -- 2. Reset Run & Payslips
    UPDATE payroll_runs SET status = 'DRAFT', journal_entry_id = NULL WHERE id = p_run_id;
    UPDATE payslips SET payment_status = 'UNPAID' WHERE run_id = p_run_id;
END;
$$;


--
-- Name: void_purchase_atomic(uuid, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.void_purchase_atomic(p_org_id uuid, p_purchase_id uuid, p_user_id uuid, p_reason text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_purchase_number TEXT;
BEGIN
    -- 1. Verifikasi PO
    SELECT purchase_number INTO v_purchase_number FROM public.purchases 
    WHERE id = p_purchase_id AND org_id = p_org_id;

    IF v_purchase_number IS NULL THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'PO tidak ditemukan');
    END IF;

    -- 2. Void Journal Entry (Ledger)
    UPDATE public.journal_entries 
    SET status = 'VOIDED',
        voided_at = NOW(),
        voided_by = p_user_id,
        void_reason = p_reason
    WHERE reference_id = p_purchase_id 
      AND reference_type = 'PURCHASE'
      AND org_id = p_org_id;

    -- 3. Delete Stock Movements (Sub-Ledger)
    DELETE FROM public.stock_movements 
    WHERE reference_id = p_purchase_id 
      AND reference_type = 'PURCHASE'
      AND org_id = p_org_id;

    -- 4. Update PO Status
    UPDATE public.purchases 
    SET status = 'VOIDED'
    WHERE id = p_purchase_id AND org_id = p_org_id;

    RETURN jsonb_build_object('success', TRUE);
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', FALSE, 'error', SQLERRM);
END;
$$;


