    credit numeric(20,2) DEFAULT 0 NOT NULL,
    memo text,
    CONSTRAINT chk_debit_or_credit CHECK (((debit > (0)::numeric) OR (credit > (0)::numeric))),
    CONSTRAINT chk_not_both CHECK ((NOT ((debit > (0)::numeric) AND (credit > (0)::numeric)))),
    CONSTRAINT journal_lines_credit_check CHECK ((credit >= (0)::numeric)),
    CONSTRAINT journal_lines_debit_check CHECK ((debit >= (0)::numeric))
);


--
-- Name: account_balances; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.account_balances AS
 SELECT a.org_id,
    a.id AS account_id,
    a.code,
    a.name,
    a.type,
    a.normal_balance,
    COALESCE(sum(jl.debit), (0)::numeric) AS total_debit,
    COALESCE(sum(jl.credit), (0)::numeric) AS total_credit,
        CASE
            WHEN (a.normal_balance = 'DEBIT'::public.normal_balance) THEN (COALESCE(sum(jl.debit), (0)::numeric) - COALESCE(sum(jl.credit), (0)::numeric))
            ELSE (COALESCE(sum(jl.credit), (0)::numeric) - COALESCE(sum(jl.debit), (0)::numeric))
        END AS balance
   FROM (public.accounts a
     LEFT JOIN ( SELECT lines.id,
            lines.entry_id,
            lines.account_id,
            lines.debit,
            lines.credit,
            lines.memo
           FROM (public.journal_lines lines
             JOIN public.journal_entries entries ON ((entries.id = lines.entry_id)))
          WHERE (entries.status = 'POSTED'::public.journal_status)) jl ON ((jl.account_id = a.id)))
  WHERE (a.is_active = true)
  GROUP BY a.org_id, a.id, a.code, a.name, a.type, a.normal_balance;


