--
-- Name: v_ap_aging_report; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_ap_aging_report AS
 WITH paid_agg AS (
         SELECT purchase_payments.purchase_id,
            COALESCE(sum((purchase_payments.amount + purchase_payments.discount_amount)), (0)::numeric) AS total_paid
           FROM public.purchase_payments
          GROUP BY purchase_payments.purchase_id
        ), return_agg AS (
         SELECT purchase_returns.purchase_id,
            COALESCE(sum(purchase_returns.total_amount), (0)::numeric) AS total_returned
           FROM public.purchase_returns
          GROUP BY purchase_returns.purchase_id
        )
 SELECT pur.org_id,
    c.name AS contact_name,
    pur.purchase_number AS doc_number,
    pur.due_date,
    pur.grand_total,
    COALESCE(p.total_paid, (0)::numeric) AS paid_amount,
    COALESCE(r.total_returned, (0)::numeric) AS returned_amount,
    ((pur.grand_total - COALESCE(p.total_paid, (0)::numeric)) - COALESCE(r.total_returned, (0)::numeric)) AS outstanding,
    GREATEST(0, (CURRENT_DATE - pur.due_date)) AS days_overdue,
        CASE
            WHEN (pur.due_date >= CURRENT_DATE) THEN 'Current'::text
            WHEN ((CURRENT_DATE - pur.due_date) <= 30) THEN '0-30 Days'::text
            WHEN ((CURRENT_DATE - pur.due_date) <= 60) THEN '31-60 Days'::text
            WHEN ((CURRENT_DATE - pur.due_date) <= 90) THEN '61-90 Days'::text
            ELSE '> 90 Days'::text
        END AS aging_bucket
   FROM (((public.purchases pur
     JOIN public.contacts c ON ((pur.vendor_id = c.id)))
     LEFT JOIN paid_agg p ON ((p.purchase_id = pur.id)))
     LEFT JOIN return_agg r ON ((r.purchase_id = pur.id)))
  WHERE ((pur.status <> ALL (ARRAY['DRAFT'::public.document_status, 'VOIDED'::public.document_status])) AND (((pur.grand_total - COALESCE(p.total_paid, (0)::numeric)) - COALESCE(r.total_returned, (0)::numeric)) > 0.01));


--
-- Name: v_ar_aging_report; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_ar_aging_report AS
 WITH paid_agg AS (
         SELECT sales_payments.sale_id,
            COALESCE(sum(sales_payments.amount), (0)::numeric) AS total_paid
           FROM public.sales_payments
          GROUP BY sales_payments.sale_id
        ), return_agg AS (
         SELECT sales_returns.sale_id,
            COALESCE(sum(sales_returns.grand_total), (0)::numeric) AS total_returned
           FROM public.sales_returns
          WHERE (sales_returns.status <> 'VOIDED'::text)
          GROUP BY sales_returns.sale_id
        )
 SELECT s.org_id,
    c.name AS contact_name,
    s.sale_number AS doc_number,
    s.due_date,
    s.grand_total,
    COALESCE(p.total_paid, (0)::numeric) AS paid_amount,
    COALESCE(r.total_returned, (0)::numeric) AS returned_amount,
    ((s.grand_total - COALESCE(p.total_paid, (0)::numeric)) - COALESCE(r.total_returned, (0)::numeric)) AS outstanding,
    GREATEST(0, (CURRENT_DATE - s.due_date)) AS days_overdue,
        CASE
            WHEN (s.due_date >= CURRENT_DATE) THEN 'Current'::text
            WHEN ((CURRENT_DATE - s.due_date) <= 30) THEN '0-30 Days'::text
            WHEN ((CURRENT_DATE - s.due_date) <= 60) THEN '31-60 Days'::text
            WHEN ((CURRENT_DATE - s.due_date) <= 90) THEN '61-90 Days'::text
            ELSE '> 90 Days'::text
        END AS aging_bucket
   FROM (((public.sales s
     JOIN public.contacts c ON ((s.customer_id = c.id)))
     LEFT JOIN paid_agg p ON ((p.sale_id = s.id)))
     LEFT JOIN return_agg r ON ((r.sale_id = s.id)))
  WHERE ((s.status <> ALL (ARRAY['DRAFT'::public.document_status, 'VOIDED'::public.document_status])) AND (((s.grand_total - COALESCE(p.total_paid, (0)::numeric)) - COALESCE(r.total_returned, (0)::numeric)) > 0.01));


--
-- Name: v_audit_red_flags; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_audit_red_flags AS
 WITH unbalanced_count AS (
         SELECT je.org_id,
            count(*) AS count
           FROM (public.journal_entries je
             JOIN public.journal_lines jl ON ((je.id = jl.entry_id)))
          WHERE (je.status = 'POSTED'::public.journal_status)
          GROUP BY je.org_id, je.id
         HAVING (sum(jl.debit) <> sum(jl.credit))
        ), late_assets AS (
         SELECT fixed_assets.org_id,
            count(*) AS count
           FROM public.fixed_assets
          WHERE ((fixed_assets.status = 'ACTIVE'::text) AND ((fixed_assets.last_depreciation_date IS NULL) OR (fixed_assets.last_depreciation_date < ((CURRENT_DATE - '1 mon'::interval))::date)))
          GROUP BY fixed_assets.org_id
        )
 SELECT o.id AS org_id,
    o.name AS org_name,
    COALESCE(u.count, (0)::numeric) AS unbalanced_journals,
    COALESCE(la.count, (0)::bigint) AS overdue_depreciation
   FROM ((public.organizations o
     LEFT JOIN ( SELECT unbalanced_count.org_id,
            sum(unbalanced_count.count) AS count
           FROM unbalanced_count
          GROUP BY unbalanced_count.org_id) u ON ((o.id = u.org_id)))
     LEFT JOIN late_assets la ON ((o.id = la.org_id)));


--
-- Name: v_budget_vs_actual; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_budget_vs_actual AS
 WITH actual_monthly AS (
         SELECT je.org_id,
            jl.account_id,
            date_trunc('month'::text, (je.entry_date)::timestamp with time zone) AS period,
            sum(
                CASE
                    WHEN (a_1.normal_balance = 'DEBIT'::public.normal_balance) THEN (jl.debit - jl.credit)
                    ELSE (jl.credit - jl.debit)
                END) AS actual_amount
           FROM ((public.journal_lines jl
             JOIN public.journal_entries je ON ((je.id = jl.entry_id)))
             JOIN public.accounts a_1 ON ((a_1.id = jl.account_id)))
          WHERE (je.status = 'POSTED'::public.journal_status)
          GROUP BY je.org_id, jl.account_id, (date_trunc('month'::text, (je.entry_date)::timestamp with time zone))
        )
 SELECT a.org_id,
    a.id AS account_id,
    a.code AS account_code,
    a.name AS account_name,
    COALESCE((b.period)::timestamp with time zone, am.period) AS period,
    COALESCE(b.budget_amount, (0)::numeric) AS budget_amount,
    COALESCE(am.actual_amount, (0)::numeric) AS actual_amount,
    (COALESCE(am.actual_amount, (0)::numeric) - COALESCE(b.budget_amount, (0)::numeric)) AS variance
   FROM ((public.accounts a
     LEFT JOIN public.budgets b ON ((b.account_id = a.id)))
     LEFT JOIN actual_monthly am ON (((am.account_id = a.id) AND (am.period = b.period))))
  WHERE (((a.type)::text = ANY (ARRAY['REVENUE'::text, 'EXPENSE'::text, 'COGS'::text])) AND ((b.budget_amount <> (0)::numeric) OR (am.actual_amount <> (0)::numeric)));


--
-- Name: v_consolidated_journal_entries; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_consolidated_journal_entries AS
 SELECT je.id,
    je.org_id,
    je.entry_number,
    je.entry_date,
    je.description,
    je.reference_type,
    je.reference_id,
    je.status,
    je.is_auto,
    je.notes,
    je.created_by,
    je.posted_at,
    je.voided_at,
    je.voided_by,
    je.void_reason,
    je.created_at,
    je.updated_at,
    je.branch_id,
    b.name AS branch_name
   FROM (public.journal_entries je
     LEFT JOIN public.branches b ON ((je.branch_id = b.id)))
  WHERE ((je.status = 'POSTED'::public.journal_status) AND (NOT (je.id IN ( SELECT intercompany_transactions.journal_entry_id
           FROM public.intercompany_transactions
          WHERE ((intercompany_transactions.is_eliminated = true) AND (intercompany_transactions.journal_entry_id IS NOT NULL))))));


--
-- Name: v_employee_details; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_employee_details AS
 SELECT e.id,
    e.org_id,
    e.user_id,
    e.nik,
    e.first_name,
    e.last_name,
    e.email,
    e.phone,
    e.date_of_birth,
    e.gender,
    e.marital_status,
    e.tax_status,
    e.job_title,
    e.department,
    e.join_date,
    e.end_date,
    e.employment_status,
    e.bank_name,
    e.bank_account_number,
    e.bank_account_holder,
    e.basic_salary,
    e.created_at,
    e.updated_at,
    o.name AS organization_name,
    (( SELECT count(*) AS count
           FROM public.attendance a
          WHERE ((a.employee_id = e.id) AND (a.record_date = CURRENT_DATE))) > 0) AS is_present_today,
    ( SELECT sum(ec.amount) AS sum
           FROM (public.employee_components ec
             JOIN public.payroll_components pc ON ((ec.component_id = pc.id)))
          WHERE ((ec.employee_id = e.id) AND (pc.type = 'EARNING'::public.payroll_item_type) AND (ec.is_active = true))) AS total_allowances
   FROM (public.employees e
     JOIN public.organizations o ON ((e.org_id = o.id)));


--
-- Name: v_internal_sla_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_internal_sla_stats AS
 SELECT org_id,
    source_type,
    count(*) AS total_requests,
    (avg((EXTRACT(epoch FROM (decided_at - requested_at)) / (3600)::numeric)))::numeric(10,2) AS avg_hours_to_decide,
    count(*) FILTER (WHERE (status = 'APPROVED'::public.approval_status)) AS total_approved,
    count(*) FILTER (WHERE (status = 'REJECTED'::public.approval_status)) AS total_rejected
   FROM public.approval_requests
  WHERE (status = ANY (ARRAY['APPROVED'::public.approval_status, 'REJECTED'::public.approval_status]))
  GROUP BY org_id, source_type;


--
-- Name: v_payroll_tax_diagnostic; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_payroll_tax_diagnostic AS
 SELECT e.org_id,
    pc.id AS component_id,
    pc.name AS component_name,
    pc.type AS component_type,
    pc.account_id,
    a.code AS account_code,
    a.name AS account_name,
        CASE
            WHEN (pc.account_id IS NULL) THEN '❌ UNMAPPED - Tidak ada akun GL'::text
            WHEN ((pc.type = 'TAX'::public.payroll_item_type) AND (a.code !~~ '2%'::text)) THEN '⚠️ WARNING - Akun pajak seharusnya di kode 2xxx (Liabilitas)'::text
            WHEN ((pc.type = 'DEDUCTION'::public.payroll_item_type) AND (a.code !~~ '2%'::text)) THEN '⚠️ WARNING - Potongan seharusnya Hutang/Liabilitas (2xxx)'::text
            WHEN ((pc.type = 'EARNING'::public.payroll_item_type) AND (a.code !~~ '5%'::text) AND (a.code !~~ '6%'::text)) THEN '⚠️ WARNING - Tunjangan seharusnya di akun Beban (5xxx/6xxx)'::text
            ELSE '✅ OK'::text
        END AS mapping_status
   FROM ((public.payroll_components pc
     LEFT JOIN public.accounts a ON ((pc.account_id = a.id)))
     JOIN public.org_members e ON ((pc.org_id = e.org_id)))
  WHERE ((e.user_id = auth.uid()) AND (e.is_active = true));


--
-- Name: VIEW v_payroll_tax_diagnostic; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_payroll_tax_diagnostic IS 'Diagnostic view untuk cek mapping akun GL pada komponen payroll. 
   Khususnya PPh 21 (akun 2202) dan BPJS (akun 2xxx).
   Menggantikan tmp_forensic_pph.mjs yang kini bisa dihapus.';


--
-- Name: v_sales_growth_analysis; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sales_growth_analysis AS
 SELECT je.org_id,
    date_trunc('month'::text, (je.entry_date)::timestamp with time zone) AS report_month,
    sum((jl.credit - jl.debit)) AS mtd_sales
   FROM ((public.journal_lines jl
     JOIN public.journal_entries je ON ((je.id = jl.entry_id)))
     JOIN public.accounts a ON ((a.id = jl.account_id)))
  WHERE ((je.status = 'POSTED'::public.journal_status) AND ((a.code ~~ '4%'::text) OR (a.type = 'REVENUE'::public.account_type)))
  GROUP BY je.org_id, (date_trunc('month'::text, (je.entry_date)::timestamp with time zone));


--
-- Name: v_tax_liability_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tax_liability_summary AS
 WITH tax_accounts AS (
         SELECT a.id,
            a.code,
            a.name,
            a.org_id
           FROM public.accounts a
          WHERE (a.code = ANY (ARRAY['1401'::text, '2201'::text, '2202'::text, '2203'::text]))
        ), tax_lines AS (
         SELECT ta.org_id,
            ta.code,
            ta.name,
            sum(jl.debit) AS total_debit,
            sum(jl.credit) AS total_credit,
            (sum(jl.credit) - sum(jl.debit)) AS balance
           FROM ((public.journal_lines jl
             JOIN public.journal_entries je ON ((jl.entry_id = je.id)))
             JOIN tax_accounts ta ON ((jl.account_id = ta.id)))
          WHERE (je.status = 'POSTED'::public.journal_status)
          GROUP BY ta.org_id, ta.code, ta.name
        )
 SELECT org_id,
    code,
    name,
    total_debit,
    total_credit,
    balance,
        CASE
            WHEN (code = '1401'::text) THEN 'PPN Masukan (VAT In) — Aset'::text
            WHEN (code = '2201'::text) THEN 'PPN Keluaran (VAT Out) — Liabilitas'::text
            WHEN (code = '2202'::text) THEN 'PPh 21 Terutang — Liabilitas (HARUS balance dengan payroll)'::text
            WHEN (code = '2203'::text) THEN 'PPh 23 Terutang — Liabilitas'::text
            ELSE 'Akun Pajak Lainnya'::text
        END AS description,
        CASE
            WHEN ((code = '2202'::text) AND (balance < (0)::numeric)) THEN '❌ ALERT: PPh 21 Debit Balance — lebih banyak pembayaran dari kewajiban! Cek mapping payroll component.'::text
            WHEN ((code = '2201'::text) AND (balance < (0)::numeric)) THEN '⚠️ Net VAT Payable negatif — lebih banyak VAT In dari VAT Out'::text
            ELSE '✅ Normal'::text
        END AS alert
   FROM tax_lines tl
  WHERE (org_id IN ( SELECT org_members.org_id
           FROM public.org_members
          WHERE ((org_members.user_id = auth.uid()) AND (org_members.is_active = true))));


--
-- Name: VIEW v_tax_liability_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_tax_liability_summary IS 'Summary saldo akun pajak per organisasi. Menggantikan forensic script.
   Alert merah pada PPh 21 mengindikasikan komponen payroll tidak ter-mapping 
   ke akun 2202 dengan benar.';


--
-- Name: verification_tokens; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.verification_tokens (
    identifier text NOT NULL,
    token text NOT NULL,
    expires timestamp with time zone NOT NULL
);


--
-- Name: warehouse_bins; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.warehouse_bins (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    org_id uuid NOT NULL,
    warehouse_id uuid NOT NULL,
    code text NOT NULL,
    description text,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    barcode text
);


--
-- Name: zakat_asset_timeline; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.zakat_asset_timeline (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    org_id uuid NOT NULL,
    total_assets numeric(19,4) NOT NULL,
    nishab_silver numeric(19,4),
    is_above_nishab boolean,
    haul_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: zakat_haul; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.zakat_haul (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    org_id uuid NOT NULL,
    haul_start_date date NOT NULL,
    gold_price_per_gram numeric NOT NULL,
    silver_price_per_gram numeric NOT NULL,
    nishab_gold numeric NOT NULL,
    nishab_silver numeric NOT NULL,
    status text DEFAULT 'ACTIVE'::text NOT NULL,
    batal_reason text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    gold_price_source text DEFAULT 'Manual Input'::text NOT NULL,
    gold_price_evidence_url text,
    gold_price_set_by uuid,
    gold_price_set_at timestamp with time zone DEFAULT now(),
    CONSTRAINT zakat_haul_status_check CHECK ((status = ANY (ARRAY['ACTIVE'::text, 'BATAL'::text, 'COMPLETED'::text, 'ARCHIVED'::text])))
);


--
-- Name: COLUMN zakat_haul.gold_price_source; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.zakat_haul.gold_price_source IS 'Sumber harga: Manual Input | Antam | Logam Mulia | Bank Indonesia | etc.';


--
-- Name: COLUMN zakat_haul.gold_price_evidence_url; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.zakat_haul.gold_price_evidence_url IS 'URL screenshot/bukti harga emas saat haul dimulai. Bukti audit.';


--
-- Name: COLUMN zakat_haul.gold_price_set_by; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.zakat_haul.gold_price_set_by IS 'User yang menginput harga emas — accountability trail.';


--
-- Name: COLUMN zakat_haul.gold_price_set_at; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.zakat_haul.gold_price_set_at IS 'Timestamp eksak harga emas diinput.';


--
-- Name: zakat_haul_events; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.zakat_haul_events (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    haul_id uuid NOT NULL,
    org_id uuid NOT NULL,
    event_date date NOT NULL,
    total_assets numeric NOT NULL,
    is_above_nishab boolean NOT NULL,
    notes text,
    created_at timestamp with time zone DEFAULT now()
);


--
-- Name: refresh_tokens id; Type: DEFAULT; Schema: auth; Owner: -
--

ALTER TABLE ONLY auth.refresh_tokens ALTER COLUMN id SET DEFAULT nextval('auth.refresh_tokens_id_seq'::regclass);


