  WHERE ((om.user_id = auth.uid()) AND (om.role = ANY (ARRAY['owner'::public.member_role, 'admin'::public.member_role, 'manager'::public.member_role, 'staff'::public.member_role])) AND (om.is_active = true) AND (je.status = 'DRAFT'::public.journal_status)))));


